python3 -c "
import json, os, sys, subprocess
from pathlib import Path
try:
    from graphify.watch import _WATCHED_EXTENSIONS
    d = json.load(sys.stdin)
    t = d.get('tool_input', d)
    fp = t.get('file_path') or t.get('path') or t.get('target_file') or t.get('TargetFile')
    if fp:
        p = Path(fp)
        try:
            p = p.resolve().relative_to(Path.cwd().resolve())
        except Exception:
            pass
        if p.suffix.lower() in _WATCHED_EXTENSIONS:
            parts = p.parts
            if not (any(part.startswith('.') for part in parts) or 'graphify-out' in parts):
                if os.path.exists('graphify-out/graph.json'):
                    cmd = [sys.executable, '-m', 'graphify.watch', '--trigger', '.']
                    kw = dict(stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, stdin=subprocess.DEVNULL, close_fds=True)
                    if os.name == 'nt':
                        flags = 0x00000008 | 0x00000200
                        try:
                            subprocess.Popen(cmd, creationflags=flags | 0x01000000, **kw)
                        except OSError:
                            subprocess.Popen(cmd, creationflags=flags, **kw)
                    else:
                        subprocess.Popen(cmd, start_new_session=True, **kw)
except Exception:
    pass
" 2>/dev/null || true
